from collections import Counter
from ag2.groupchat import GroupChat

def detect_false_consensus(chat_history: list, known_facts: dict):
    claims = Counter()
    agreeing_agents = Counter()

    for message in chat_history[-10:]:
        if message.role == 'user' or message.content.startswith('I agree'):
            continue

        # Extract potential factual claims (simplified regex)
        claim = extract_claim(message.content)
        if claim:
            claims[claim] += 1
            agreeing_agents[f'{message.sender}_{claim}'] += 1

    suspicious = []
    for claim, count in claims.items():
        if count >= 3 and claim not in known_facts:
            suspicious.append({
                'claim': claim,
                'support_count': count,
                'agents': len(set(k.split('_')[0] for k in agreeing_agents if claim in k))
            })
    return suspicious

def extract_claim(text: str) -> str:
    import re
    numbers = re.findall(r'\d+', text)
    return ' '.join(numbers[:3]) if numbers else ''

