from ag2.hooks import MessageHook
from ag2.messages import Message

class TopicEnforcerHook(MessageHook):
    def __init__(self, task_prompt: str):
        self.task_prompt = task_prompt
        self.drift_count = 0
        self.max_drift = 3

    def on_message(self, message: Message) -> Message:
        if self.detect_drift(message):
            self.drift_count += 1
            if self.drift_count >= self.max_drift:
                redirect = f"\n\n*** STAY ON TASK ***\nOriginal task: {self.task_prompt}\nPlease address the actual request above."
                message.content += redirect
                self.drift_count = 0
        return message

    def detect_drift(self, message: Message) -> bool:
        off_topic_keywords = ['by the way', 'also', 'tangent', 'randomly']
        return any(kw in message.content.lower() for kw in off_topic_keywords)

# Usage
hook = TopicEnforcerHook('Analyze Q3 sales data')
chat = GroupChat(agents, message_hooks=[hook])

import ast
import subprocess
import tempfile
from ag2.agents import CodeAgent

class SafeCodeAgent(CodeAgent):
    DANGEROUS_APIS = {
        'os.remove', 'os.rmdir', 'shutil.rmtree',
        'requests.', 'urllib.', 'subprocess.',
        'open('  # File writes
    }

    def execute_code(self, code: str) -> str:
        tree = ast.parse(code)
        dangerous_calls = []

        for node in ast.walk(tree):
            if isinstance(node, ast.Call):
                func_name = ast.unparse(node.func)
                if any(dangerous in func_name for dangerous in self.DANGEROUS_APIS):
                    dangerous_calls.append(func_name)

        if dangerous_calls:
            return f"SECURITY BLOCK: Dangerous operations detected: {dangerous_calls}"

        # Safe execution in temp sandbox
        with tempfile.TemporaryDirectory() as sandbox:
            result = subprocess.run(
                ['python', '-c', code],
                cwd=sandbox, capture_output=True, text=True, timeout=30
            )
            return result.stdout + result.stderr
